const shareMilestone = (badge,pct) => {
  const msg = pct===1
    ? `I just earned ${badge.icon} ${badge.label} on MahjSpace \u2014 my first hand of the 2026 card! Start charting your progress: mahjspace.com`
    : `I just earned ${badge.icon} ${badge.label} on MahjSpace \u2014 ${pct}% complete! Start charting your progress: mahjspace.com`;
  if (navigator.share) navigator.share({text:msg}).catch(()=>{});
  else { navigator.clipboard?.writeText(msg); alert("Copied to clipboard!"); }
};

const sendEmail = async (to, subject, html) => {
  try { await addDoc(collection(db,"mail"),{to,message:{subject,html}}); } catch(e){ console.error("Email error:",e); }
};

function HandTiles({text}) {
  const groups = text.split(" ");
  const suitColors = ["#E06060","#4EAE6A","#5A8ED8"];
  let suitIdx = 0;
  const assigned = {};
  return <>{groups.map((g,i)=>{
    const isNum = /^[0-9]+$/.test(g);
    let color = "#E8E6E1";
    if(isNum){ if(assigned[g]!==undefined) color=suitColors[assigned[g]]; else { color=suitColors[suitIdx%3]; assigned[g]=suitIdx%3; suitIdx++; } }
    return <span key={i}><span style={{color}}>{g}</span>{i<groups.length-1?" ":""}</span>;
  })}</>;
}

